// Scheduled posts queue
// Add posts here when ready to schedule
// Set 'approved: true' only after user review
// Set 'posted: true' after successful posting
const staticData = $getWorkflowStaticData('global');

if (!staticData.queue) {
  // Initialize with empty queue
  // To schedule a post, add it to this queue via n8n UI
  staticData.queue = [
    // Example format:
    // {
    //   id: 'show-hn-1',
    //   platform: 'twitter',
    //   scheduledDate: '2026-03-18T14:00:00Z',
    //   content: 'Tweet text here',
    //   approved: false,
    //   posted: false
    // }
  ];
}

const now = new Date();
const pendingPosts = staticData.queue.filter(p => 
  p.approved && 
  !p.posted && 
  new Date(p.scheduledDate) <= now
);

if (pendingPosts.length === 0) {
  return [{ json: { hasPosts: false, message: 'No posts due' } }];
}

return pendingPosts.map(p => ({ json: { ...p, hasPosts: true } }));

// Mark post as posted in the queue
const staticData = $getWorkflowStaticData('global');
const postId = $input.first().json.id;
const post = staticData.queue.find(p => p.id === postId);
if (post) {
  post.posted = true;
  post.postedAt = new Date().toISOString();
}
return [{ json: { success: true, postId, postedAt: new Date().toISOString() } }];
